```typescript
export type TournamentState =
  | { status: "none" }
  | { status: "draft"; id: string; name: string; teams: string[] }
  | { status: "running"; id: string; name: string; teams: string[]; startedAt: string }
  | { status: "finished"; id: string; name: string; champion: string };

export type TournamentCommand =
  | { type: "create"; id: string; name: string }
  | { type: "enrol"; team: string }
  | { type: "start"; at: string }
  | { type: "finish"; champion: string };

export type TournamentEvent =
  | { type: "TournamentCreated"; id: string; name: string }
  | { type: "TournamentTeamEnrolled"; team: string }
  | { type: "TournamentStarted"; at: string }
  | { type: "TournamentFinished"; champion: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const tournamentDecider: Decider<TournamentCommand, TournamentEvent, TournamentState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "create":
        if (state.status !== "none") throw new DomainError("ALREADY_EXISTS");
        return [{ type: "TournamentCreated", id: command.id, name: command.name }];
      case "enrol":
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        if (state.teams.includes(command.team)) throw new DomainError("DUPLICATE_TEAM");
        return [{ type: "TournamentTeamEnrolled", team: command.team }];
      case "start":
        if (state.status !== "draft") throw new DomainError("NOT_DRAFT");
        if (state.teams.length < 2) throw new DomainError("NEED_TWO_TEAMS");
        return [{ type: "TournamentStarted", at: command.at }];
      case "finish":
        if (state.status !== "running") throw new DomainError("NOT_RUNNING");
        return [{ type: "TournamentFinished", champion: command.champion }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "TournamentCreated":
        return { status: "draft", id: event.id, name: event.name, teams: [] };
      case "TournamentTeamEnrolled":
        if (state.status !== "draft") return state;
        return { ...state, teams: [...state.teams, event.team] };
      case "TournamentStarted":
        if (state.status !== "draft") return state;
        return { status: "running", id: state.id, name: state.name, teams: state.teams, startedAt: event.at };
      case "TournamentFinished":
        if (state.status !== "running") return state;
        return { status: "finished", id: state.id, name: state.name, champion: event.champion };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

```typescript
export type MatchState =
  | { status: "none" }
  | { status: "scheduled"; id: string; home: string; away: string; kickoffAt: string }
  | { status: "live"; id: string; home: string; away: string; homeGoals: number; awayGoals: number }
  | { status: "final"; id: string; home: string; away: string; homeGoals: number; awayGoals: number };

export type MatchCommand =
  | { type: "schedule"; id: string; home: string; away: string; kickoffAt: string }
  | { type: "kickoff" }
  | { type: "goal"; side: "home" | "away"; scorer: string }
  | { type: "fullTime" };

export type MatchEvent =
  | { type: "MatchScheduled"; id: string; home: string; away: string; kickoffAt: string }
  | { type: "MatchKickedOff" }
  | { type: "MatchGoalScored"; side: "home" | "away"; scorer: string }
  | { type: "MatchFullTime" };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const matchDecider: Decider<MatchCommand, MatchEvent, MatchState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "schedule":
        if (state.status !== "none") throw new DomainError("ALREADY_SCHEDULED");
        if (command.home === command.away) throw new DomainError("SAME_OPPONENT");
        return [{ type: "MatchScheduled", id: command.id, home: command.home, away: command.away, kickoffAt: command.kickoffAt }];
      case "kickoff":
        if (state.status !== "scheduled") throw new DomainError("NOT_SCHEDULED");
        return [{ type: "MatchKickedOff" }];
      case "goal":
        if (state.status !== "live") throw new DomainError("NOT_LIVE");
        return [{ type: "MatchGoalScored", side: command.side, scorer: command.scorer }];
      case "fullTime":
        if (state.status !== "live") throw new DomainError("NOT_LIVE");
        return [{ type: "MatchFullTime" }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "MatchScheduled":
        return { status: "scheduled", id: event.id, home: event.home, away: event.away, kickoffAt: event.kickoffAt };
      case "MatchKickedOff":
        if (state.status !== "scheduled") return state;
        return { status: "live", id: state.id, home: state.home, away: state.away, homeGoals: 0, awayGoals: 0 };
      case "MatchGoalScored":
        if (state.status !== "live") return state;
        return event.side === "home"
          ? { ...state, homeGoals: state.homeGoals + 1 }
          : { ...state, awayGoals: state.awayGoals + 1 };
      case "MatchFullTime":
        if (state.status !== "live") return state;
        return { status: "final", id: state.id, home: state.home, away: state.away, homeGoals: state.homeGoals, awayGoals: state.awayGoals };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
```

A Season aggregate is a pure Decider: `initialState` is an empty marker, `decide` validates a command against the current state and emits events, and `evolve` folds those events back into state. Opening a season moves it from none to open; matches can only be scheduled while open; closing it freezes the set of matches and emits a champion. No I/O lives in the core.

```typescript
export type SeasonState =
  | { status: "none" }
  | { status: "open"; id: string; year: number; matches: string[] }
  | { status: "closed"; id: string; year: number; matches: string[]; champion: string };

export type SeasonCommand =
  | { type: "open"; id: string; year: number }
  | { type: "scheduleMatch"; matchId: string }
  | { type: "close"; champion: string };

export type SeasonEvent =
  | { type: "SeasonOpened"; id: string; year: number }
  | { type: "SeasonMatchScheduled"; matchId: string }
  | { type: "SeasonClosed"; champion: string };

export class SeasonError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const seasonDecider: Decider<SeasonCommand, SeasonEvent, SeasonState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "open":
        if (s.status !== "none") throw new SeasonError("ALREADY_OPEN");
        if (c.year < 1900) throw new SeasonError("INVALID_YEAR");
        return [{ type: "SeasonOpened", id: c.id, year: c.year }];
      case "scheduleMatch":
        if (s.status !== "open") throw new SeasonError("NOT_OPEN");
        if (s.matches.includes(c.matchId)) throw new SeasonError("DUPLICATE_MATCH");
        return [{ type: "SeasonMatchScheduled", matchId: c.matchId }];
      case "close":
        if (s.status !== "open") throw new SeasonError("NOT_OPEN");
        if (s.matches.length === 0) throw new SeasonError("NO_MATCHES");
        return [{ type: "SeasonClosed", champion: c.champion }];
      default: {
        const _never: never = c;
        throw new SeasonError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "SeasonOpened":
        return { status: "open", id: e.id, year: e.year, matches: [] };
      case "SeasonMatchScheduled":
        if (s.status !== "open") return s;
        return { ...s, matches: [...s.matches, e.matchId] };
      case "SeasonClosed":
        if (s.status !== "open") return s;
        return { status: "closed", id: s.id, year: s.year, matches: s.matches, champion: e.champion };
      default: {
        const _never: never = e;
        return s;
      }
    }
  },
};
