```typescript
export type PlayerState =
  | { status: "none" }
  | { status: "active"; id: string; name: string; club: string }
  | { status: "retired"; id: string; name: string };

export type PlayerCommand =
  | { type: "sign"; id: string; name: string; club: string }
  | { type: "transfer"; toClub: string }
  | { type: "retire"; reason: string };

export type PlayerEvent =
  | { type: "PlayerSigned"; id: string; name: string; club: string }
  | { type: "PlayerTransferred"; fromClub: string; toClub: string }
  | { type: "PlayerRetired"; reason: string };

export class DomainError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "DomainError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(command: C, state: S): E[];
  evolve(state: S, event: E): S;
}

export const playerDecider: Decider<PlayerCommand, PlayerEvent, PlayerState> = {
  initialState: { status: "none" },
  decide(command, state) {
    switch (command.type) {
      case "sign":
        if (state.status !== "none") throw new DomainError("ALREADY_SIGNED");
        if (command.name.trim().length === 0) throw new DomainError("EMPTY_NAME");
        return [{ type: "PlayerSigned", id: command.id, name: command.name, club: command.club }];
      case "transfer":
        if (state.status === "retired") throw new DomainError("RETIRED");
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        if (state.club === command.toClub) throw new DomainError("SAME_CLUB");
        return [{ type: "PlayerTransferred", fromClub: state.club, toClub: command.toClub }];
      case "retire":
        if (state.status !== "active") throw new DomainError("NOT_ACTIVE");
        return [{ type: "PlayerRetired", reason: command.reason }];
      default: {
        const _never: never = command;
        throw new DomainError("UNKNOWN");
      }
    }
  },
  evolve(state, event) {
    switch (event.type) {
      case "PlayerSigned":
        return { status: "active", id: event.id, name: event.name, club: event.club };
      case "PlayerTransferred":
        if (state.status !== "active") return state;
        return { ...state, club: event.toClub };
      case "PlayerRetired":
        if (state.status !== "active") return state;
        return { status: "retired", id: state.id, name: state.name };
      default: {
        const _never: never = event;
        return state;
      }
    }
  },
};
