A League tracks member clubs and each club's tier; a promote/demote shifts a club by one tier. The Decider is a pure triple over a discriminated state union.

```typescript
export type LeagueState =
  | { status: "none" }
  | { status: "active"; id: string; clubs: Record<string, number> };

export type LeagueCommand =
  | { type: "found"; id: string }
  | { type: "register"; club: string; tier: number }
  | { type: "promote"; club: string }
  | { type: "demote"; club: string };

export type LeagueEvent =
  | { type: "LeagueFounded"; id: string }
  | { type: "LeagueClubRegistered"; club: string; tier: number }
  | { type: "LeagueClubPromoted"; club: string; newTier: number }
  | { type: "LeagueClubDemoted"; club: string; newTier: number };

export class LeagueError extends Error {}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const leagueDecider: Decider<LeagueCommand, LeagueEvent, LeagueState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "found":
        if (s.status !== "none") throw new LeagueError("ALREADY_FOUNDED");
        return [{ type: "LeagueFounded", id: c.id }];
      case "register":
        if (s.status !== "active") throw new LeagueError("NOT_ACTIVE");
        if (c.club in s.clubs) throw new LeagueError("DUPLICATE_CLUB");
        if (c.tier < 1) throw new LeagueError("INVALID_TIER");
        return [{ type: "LeagueClubRegistered", club: c.club, tier: c.tier }];
      case "promote": {
        if (s.status !== "active") throw new LeagueError("NOT_ACTIVE");
        const cur = s.clubs[c.club];
        if (cur === undefined) throw new LeagueError("UNKNOWN_CLUB");
        if (cur <= 1) throw new LeagueError("TOP_TIER");
        return [{ type: "LeagueClubPromoted", club: c.club, newTier: cur - 1 }];
      }
      case "demote": {
        if (s.status !== "active") throw new LeagueError("NOT_ACTIVE");
        const cur = s.clubs[c.club];
        if (cur === undefined) throw new LeagueError("UNKNOWN_CLUB");
        return [{ type: "LeagueClubDemoted", club: c.club, newTier: cur + 1 }];
      }
      default: {
        const _never: never = c;
        throw new LeagueError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "LeagueFounded":
        return { status: "active", id: e.id, clubs: {} };
      case "LeagueClubRegistered":
        if (s.status !== "active") return s;
        return { ...s, clubs: { ...s.clubs, [e.club]: e.tier } };
      case "LeagueClubPromoted":
      case "LeagueClubDemoted":
        if (s.status !== "active") return s;
        return { ...s, clubs: { ...s.clubs, [e.club]: e.newTier } };
      default: {
        const _never: never = e;
        return s;
      }
    }
  },
};
```

```typescript
export type TeamRosterState =
  | { status: "none" }
  | { status: "formed"; id: string; players: string[]; captain: string | null };

export type TeamRosterCommand =
  | { type: "form"; id: string }
  | { type: "addPlayer"; playerId: string }
  | { type: "releasePlayer"; playerId: string }
  | { type: "setCaptain"; playerId: string };

export type TeamRosterEvent =
  | { type: "TeamRosterFormed"; id: string }
  | { type: "TeamRosterPlayerAdded"; playerId: string }
  | { type: "TeamRosterPlayerReleased"; playerId: string }
  | { type: "TeamRosterCaptainSet"; playerId: string };

export class RosterError extends Error {
  constructor(public readonly code: string) { super(code); this.name = "RosterError"; }
}

export interface Decider<C, E, S> {
  readonly initialState: S;
  decide(c: C, s: S): E[];
  evolve(s: S, e: E): S;
}

export const teamRosterDecider: Decider<TeamRosterCommand, TeamRosterEvent, TeamRosterState> = {
  initialState: { status: "none" },
  decide(c, s) {
    switch (c.type) {
      case "form":
        if (s.status !== "none") throw new RosterError("ALREADY_FORMED");
        return [{ type: "TeamRosterFormed", id: c.id }];
      case "addPlayer":
        if (s.status !== "formed") throw new RosterError("NOT_FORMED");
        if (s.players.includes(c.playerId)) throw new RosterError("ALREADY_ON_ROSTER");
        if (s.players.length >= 25) throw new RosterError("ROSTER_FULL");
        return [{ type: "TeamRosterPlayerAdded", playerId: c.playerId }];
      case "releasePlayer":
        if (s.status !== "formed") throw new RosterError("NOT_FORMED");
        if (!s.players.includes(c.playerId)) throw new RosterError("NOT_ON_ROSTER");
        return [{ type: "TeamRosterPlayerReleased", playerId: c.playerId }];
      case "setCaptain":
        if (s.status !== "formed") throw new RosterError("NOT_FORMED");
        if (!s.players.includes(c.playerId)) throw new RosterError("NOT_ON_ROSTER");
        return [{ type: "TeamRosterCaptainSet", playerId: c.playerId }];
      default: {
        const _never: never = c;
        throw new RosterError("UNKNOWN");
      }
    }
  },
  evolve(s, e) {
    switch (e.type) {
      case "TeamRosterFormed":
        return { status: "formed", id: e.id, players: [], captain: null };
      case "TeamRosterPlayerAdded":
        if (s.status !== "formed") return s;
        return { ...s, players: [...s.players, e.playerId] };
      case "TeamRosterPlayerReleased":
        if (s.status !== "formed") return s;
        return {
          ...s,
          players: s.players.filter((p) => p !== e.playerId),
          captain: s.captain === e.playerId ? null : s.captain,
        };
      case "TeamRosterCaptainSet":
        if (s.status !== "formed") return s;
        return { ...s, captain: e.playerId };
      default: {
        const _never: never = e;
        return s;
      }
    }
  },
};
```

```typescript
export type MatchEvent =
  | { type: "MatchScheduled"; id: string; home: string; away: string }
  | { type: "MatchKickedOff"; id: string }
  | { type: "MatchFullTime"; id: string; home: string; away: string; homeGoals: number; awayGoals: number };

export interface StandingsRow {
  club: string;
  played: number;
  won: number;
  drawn: number;
  lost: number;
  gf: number;
  ga: number;
  points: number;
}

export type StandingsView = Record<string, StandingsRow>;

export const emptyStandings: StandingsView = {};

function ensure(view: StandingsView, club: string): StandingsRow {
  return view[club] ?? { club, played: 0, won: 0, drawn: 0, lost: 0, gf: 0, ga: 0, points: 0 };
}

export function project(view: StandingsView, event: MatchEvent): StandingsView {
  switch (event.type) {
    case "MatchScheduled":
    case "MatchKickedOff":
      return view;
    case "MatchFullTime": {
      const home = ensure(view, event.home);
      const away = ensure(view, event.away);
      const homeWon = event.homeGoals > event.awayGoals;
      const draw = event.homeGoals === event.awayGoals;
      const nextHome: StandingsRow = {
        ...home,
        played: home.played + 1,
        won: home.won + (homeWon ? 1 : 0),
        drawn: home.drawn + (draw ? 1 : 0),
        lost: home.lost + (!homeWon && !draw ? 1 : 0),
        gf: home.gf + event.homeGoals,
        ga: home.ga + event.awayGoals,
        points: home.points + (homeWon ? 3 : draw ? 1 : 0),
      };
      const nextAway: StandingsRow = {
        ...away,
        played: away.played + 1,
        won: away.won + (!homeWon && !draw ? 1 : 0),
        drawn: away.drawn + (draw ? 1 : 0),
        lost: away.lost + (homeWon ? 1 : 0),
        gf: away.gf + event.awayGoals,
        ga: away.ga + event.homeGoals,
        points: away.points + (!homeWon && !draw ? 3 : draw ? 1 : 0),
      };
      return { ...view, [event.home]: nextHome, [event.away]: nextAway };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function buildStandings(events: readonly MatchEvent[]): StandingsView {
  return events.reduce(project, emptyStandings);
}
```

A projection is a distinct fold from the aggregate `evolve`: it denormalises events into a query-friendly shape and returns the view unchanged for events outside its interest.

```typescript
export type PlayerStatEvent =
  | { type: "MatchGoalScored"; matchId: string; scorer: string; minute: number }
  | { type: "MatchKickedOff"; matchId: string }
  | { type: "MatchFullTime"; matchId: string };

export interface PlayerTally {
  player: string;
  goals: number;
}

export type GoalTallyView = Record<string, PlayerTally>;

export const emptyTally: GoalTallyView = {};

export function project(view: GoalTallyView, event: PlayerStatEvent): GoalTallyView {
  switch (event.type) {
    case "MatchGoalScored": {
      const prev = view[event.scorer] ?? { player: event.scorer, goals: 0 };
      return { ...view, [event.scorer]: { ...prev, goals: prev.goals + 1 } };
    }
    case "MatchKickedOff":
    case "MatchFullTime":
      return view;
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function buildTally(events: readonly PlayerStatEvent[]): GoalTallyView {
  return events.reduce(project, emptyTally);
}

export function topScorers(view: GoalTallyView, n: number): PlayerTally[] {
  return Object.values(view).sort((a, b) => b.goals - a.goals).slice(0, n);
}
```

