Here is a re-typed projection with a compiled filter: `buildSchedule` takes the competition id to exclude, and the event union is exhaustive with a `never` default.

```typescript
export type ScheduleEvent =
  | { type: "MatchScheduled"; id: string; competition: string; kickoffAt: string; home: string; away: string }
  | { type: "MatchRescheduled"; id: string; kickoffAt: string }
  | { type: "MatchCancelled"; id: string };

export interface ScheduleEntry {
  id: string;
  competition: string;
  kickoffAt: string;
  home: string;
  away: string;
  cancelled: boolean;
}

export type ScheduleView = Record<string, ScheduleEntry>;

export const emptySchedule: ScheduleView = {};

export function project(view: ScheduleView, event: ScheduleEvent, excludeCompetition: string | null = null): ScheduleView {
  switch (event.type) {
    case "MatchScheduled":
      if (excludeCompetition !== null && event.competition === excludeCompetition) return view;
      return {
        ...view,
        [event.id]: {
          id: event.id,
          competition: event.competition,
          kickoffAt: event.kickoffAt,
          home: event.home,
          away: event.away,
          cancelled: false,
        },
      };
    case "MatchRescheduled": {
      const existing = view[event.id];
      if (!existing) return view;
      return { ...view, [event.id]: { ...existing, kickoffAt: event.kickoffAt } };
    }
    case "MatchCancelled": {
      const existing = view[event.id];
      if (!existing) return view;
      return { ...view, [event.id]: { ...existing, cancelled: true } };
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}

export function buildSchedule(events: readonly ScheduleEvent[], excludeCompetition: string | null = null): ScheduleView {
  return events.reduce<ScheduleView>((v, e) => project(v, e, excludeCompetition), emptySchedule);
}
```

```typescript
export type PenaltyBoxEvent =
  | { type: "SanctionIssued"; matchId: string; playerId: string; minutes: number; at: string }
  | { type: "SanctionServed"; matchId: string; playerId: string; at: string }
  | { type: "MatchFullTime"; matchId: string };

export interface PenaltyBoxRow {
  matchId: string;
  playerId: string;
  minutesRemaining: number;
  servedAt: string | null;
}

export type PenaltyBoxView = Record<string, PenaltyBoxRow>;

export const emptyPenaltyBox: PenaltyBoxView = {};

function key(matchId: string, playerId: string): string {
  return `${matchId}:${playerId}`;
}

export function project(view: PenaltyBoxView, event: PenaltyBoxEvent): PenaltyBoxView {
  switch (event.type) {
    case "SanctionIssued": {
      const k = key(event.matchId, event.playerId);
      return {
        ...view,
        [k]: { matchId: event.matchId, playerId: event.playerId, minutesRemaining: event.minutes, servedAt: null },
      };
    }
    case "SanctionServed": {
      const k = key(event.matchId, event.playerId);
      const existing = view[k];
      if (!existing) return view;
      return { ...view, [k]: { ...existing, minutesRemaining: 0, servedAt: event.at } };
    }
    case "MatchFullTime": {
      const filtered: PenaltyBoxView = {};
      for (const [k, row] of Object.entries(view)) {
        if (row.matchId !== event.matchId) filtered[k] = row;
      }
      return filtered;
    }
    default: {
      const _never: never = event;
      return view;
    }
  }
}
