```typescript
export interface Snapshot<S> {
  version: number;
  state: S;
}

export const CURRENT_VERSION = 3 as const;

export interface TournamentV1 { id: string; status: string; teams: string[]; }
export interface TournamentV2 { id: string; status: string; teams: string[]; region: string; }
export interface TournamentV3 {
  id: string;
  status: "draft" | "running" | "finished";
  teams: string[];
  region: string;
  format: "roundRobin" | "knockout";
}

export type CurrentState = TournamentV3;

function v1Tov2(snap: Snapshot<TournamentV1>): Snapshot<TournamentV2> {
  return { version: 2, state: { ...snap.state, region: "unknown" } };
}

function v2Tov3(snap: Snapshot<TournamentV2>): Snapshot<TournamentV3> {
  const status = (["draft", "running", "finished"] as const).find((s) => s === snap.state.status) ?? "draft";
  return { version: 3, state: { ...snap.state, status, format: "roundRobin" } };
}

export function upgradeSnapshot(raw: Snapshot<unknown>): Snapshot<CurrentState> {
  let current: Snapshot<unknown> = raw;
  if (current.version === 1) current = v1Tov2(current as Snapshot<TournamentV1>);
  if (current.version === 2) current = v2Tov3(current as Snapshot<TournamentV2>);
  if (current.version !== CURRENT_VERSION) throw new Error(`UNSUPPORTED_SNAPSHOT_VERSION:${current.version}`);
  return current as Snapshot<CurrentState>;
}

export function loadTournamentSnapshot(raw: unknown): CurrentState {
  if (typeof raw !== "object" || raw === null) throw new Error("INVALID_SNAPSHOT");
  const snap = raw as Snapshot<unknown>;
  if (typeof snap.version !== "number") throw new Error("MISSING_VERSION");
  return upgradeSnapshot(snap).state;
}
```

Snapshots avoid re-folding long event streams by persisting state plus a version tag. When the schema evolves, a loader runs the right chain of upgraders in order so older snapshots are migrated at read time without rewriting any events. The decider keeps its pure contract; the upgrade logic lives entirely at the storage boundary.

