```typescript
export type MatchEvent =
  | { type: "MatchScheduled"; id: string; home: string; away: string }
  | { type: "MatchKickedOff" }
  | { type: "MatchFullTime"; homeGoals: number; awayGoals: number };

export type ExpectedRevision = bigint | "no_stream" | "any";

export interface StoredEvent<E> {
  revision: bigint;
  event: E;
}

export interface EventStore {
  readStream<E>(stream: string): Promise<ReadonlyArray<StoredEvent<E>>>;
  appendToStream<E>(stream: string, events: readonly E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {
  constructor(public readonly stream: string, public readonly expected: ExpectedRevision) {
    super(`CONCURRENCY_CONFLICT:${stream}`);
    this.name = "ConcurrencyConflict";
  }
}

export interface StoreRejection {
  kind: "concurrency";
}

export async function appendMatchEvents(
  store: EventStore,
  stream: string,
  newEvents: readonly MatchEvent[],
): Promise<bigint> {
  const stored = await store.readStream<MatchEvent>(stream);
  const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
  try {
    const result = await store.appendToStream<MatchEvent>(stream, newEvents, { expectedRevision: expected });
    return result.nextRevision;
  } catch (err) {
    const rejection = err as Partial<StoreRejection>;
    if (rejection.kind === "concurrency") throw new ConcurrencyConflict(stream, expected);
    throw err;
  }
}
```

The idiom is: read the last revision, decide, and append with `expectedRevision` set to that revision. On conflict, re-read and retry once; a second conflict bubbles up as a typed `ConcurrencyConflict` so callers can apply their own backoff.

```typescript
export type PlayerEvent =
  | { type: "PlayerSigned"; id: string; club: string }
  | { type: "PlayerTransferred"; toClub: string };

export type ExpectedRevision = bigint | "no_stream";

export interface StoredEvent<E> {
  revision: bigint;
  event: E;
}

export interface EventStore {
  readStream<E>(stream: string): Promise<ReadonlyArray<StoredEvent<E>>>;
  appendToStream<E>(stream: string, events: readonly E[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class ConcurrencyConflict extends Error {}

export async function appendWithRetry(
  store: EventStore,
  stream: string,
  decide: (events: readonly PlayerEvent[]) => readonly PlayerEvent[],
): Promise<bigint> {
  for (let attempt = 0; attempt < 2; attempt++) {
    const stored = await store.readStream<PlayerEvent>(stream);
    const expected: ExpectedRevision = stored.length === 0 ? "no_stream" : stored[stored.length - 1]!.revision;
    const newEvents = decide(stored.map((s) => s.event));
    try {
      const result = await store.appendToStream<PlayerEvent>(stream, newEvents, { expectedRevision: expected });
      return result.nextRevision;
    } catch (err) {
      const e = err as { kind?: string };
      if (e.kind !== "concurrency") throw err;
    }
  }
  throw new ConcurrencyConflict("retry exhausted");
}
```

