  if (c.type !== "record") { const _n: never = c.type; throw new Error("UNKNOWN"); }
  if (s.status !== "none") throw new Error("ALREADY_RECORDED");
  if (c.minute < 0) throw new Error("INVALID_MINUTE");
  return [{ type: "GoalRecorded", id: c.id, scorer: c.scorer, minute: c.minute, matchId: c.matchId }];
}

export function evolve(s: GoalState, e: GoalEvent): GoalState {
  if (e.type !== "GoalRecorded") { const _n: never = e.type; return s; }
  return { status: "recorded", id: e.id, scorer: e.scorer, minute: e.minute, matchId: e.matchId };
}

export type ExpectedRevision = bigint | "no_stream";

