    case "SanctionServed":
      if (s.status !== "issued") return s;
      return { status: "served", id: s.id, playerId: s.playerId, servedAt: e.at };
    case "SanctionRescinded":
      if (s.status !== "issued") return s;
      return { status: "rescinded", id: s.id, reason: e.reason };
    default: { const _n: never = e; return s; }
