```typescript
export type MatchEvent =
  | { type: "MatchFullTime"; home: string; away: string; homeGoals: number; awayGoals: number }
  | { type: "MatchKickedOff"; id: string };

export interface StandingsRow {
  club: string;
  played: number;
  points: number;
}

export type StandingsView = Record<string, StandingsRow>;

export function project(view: StandingsView, e: MatchEvent): StandingsView {
  switch (e.type) {
    case "MatchKickedOff":
      return view;
    case "MatchFullTime": {
      const h = view[e.home] ?? { club: e.home, played: 0, points: 0 };
      const a = view[e.away] ?? { club: e.away, played: 0, points: 0 };
      const hw = e.homeGoals > e.awayGoals, draw = e.homeGoals === e.awayGoals;
      return {
        ...view,
        [e.home]: { ...h, played: h.played + 1, points: h.points + (hw ? 3 : draw ? 1 : 0) },
        [e.away]: { ...a, played: a.played + 1, points: a.points + (!hw && !draw ? 3 : draw ? 1 : 0) },
      };
    }
    default: { const _n: never = e; return view; }
  }
}

export interface CheckpointStore {
  read(name: string): Promise<bigint | null>;
  write(name: string, position: bigint): Promise<void>;
}

export interface ReadModelStore {
  load(): Promise<StandingsView>;
  save(view: StandingsView): Promise<void>;
}

export interface StreamSource {
  iterate(from: bigint): AsyncIterable<{ position: bigint; event: MatchEvent }>;
}

export async function runSubscription(
  name: string,
  source: StreamSource,
  checkpoints: CheckpointStore,
  readModel: ReadModelStore,
): Promise<void> {
  const start = (await checkpoints.read(name)) ?? 0n;
  let view = await readModel.load();
  async function run() {
    for await (const { position, event } of source.iterate(start)) {
      view = project(view, event);
      await readModel.save(view);
      await checkpoints.write(name, position);
    }
  }
  await run();
}
```

Write the checkpoint only AFTER the projection has been applied; otherwise a crash between apply and save of the checkpoint would skip events. Keep the checkpoint store separate from the read model so a rebuild can reset one without the other.

