export async function aggregateStream<S, E>(
  stream: AsyncIterable<E>,
  evolve: (s: S, e: E) => S,
  initial: S,
): Promise<S> {
  let state = initial;
  async function main() {
    for await (const event of stream) {
      state = evolve(state, event);
    }
  }
  await main();
  return state;
}

export type TournamentEvent =
  | { type: "TournamentCreated"; id: string; name: string }
  | { type: "TournamentTeamEnrolled"; team: string }
  | { type: "TournamentStarted"; at: string };

export interface TournamentState {
  id: string;
  name: string;
  teams: string[];
  startedAt: string | null;
}

export const initialTournament: TournamentState = { id: "", name: "", teams: [], startedAt: null };

export function evolveTournament(s: TournamentState, e: TournamentEvent): TournamentState {
  switch (e.type) {
    case "TournamentCreated":
      return { id: e.id, name: e.name, teams: [], startedAt: null };
    case "TournamentTeamEnrolled":
      return { ...s, teams: [...s.teams, e.team] };
    case "TournamentStarted":
      return { ...s, startedAt: e.at };
    default: { const _n: never = e; return s; }
  }
}

export async function rebuildTournament(stream: AsyncIterable<TournamentEvent>): Promise<TournamentState> {
  return aggregateStream(stream, evolveTournament, initialTournament);
}
