export type StoredGoalEvent =
  | { type: "GoalScored"; version: 1; matchId: string; minute: number; player: string }
  | { type: "GoalScored"; version: 2; matchId: string; minute: number; scorerId: string; scorerName: string };

export interface CurrentGoalEvent {
  type: "GoalScored";
  matchId: string;
  minute: number;
  scorerId: string;
  scorerName: string;
}

export class UnknownEventError extends Error {
  constructor(payload: unknown) {
    super(`UNKNOWN_EVENT:${JSON.stringify(payload)}`);
    this.name = "UnknownEventError";
  }
}

function isStoredGoal(raw: unknown): raw is StoredGoalEvent {
  if (typeof raw !== "object" || raw === null) return false;
  const r = raw as { type?: unknown; version?: unknown };
  return r.type === "GoalScored" && (r.version === 1 || r.version === 2);
}

export function upcast(raw: unknown): CurrentGoalEvent {
  if (!isStoredGoal(raw)) throw new UnknownEventError(raw);
  switch (raw.version) {
    case 1:
      return {
        type: "GoalScored",
        matchId: raw.matchId,
        minute: raw.minute,
        scorerId: raw.player,
        scorerName: raw.player,
      };
    case 2:
      return {
        type: "GoalScored",
        matchId: raw.matchId,
        minute: raw.minute,
        scorerId: raw.scorerId,
        scorerName: raw.scorerName,
      };
    default: {
      const _never: never = raw;
      throw new UnknownEventError(raw);
    }
  }
}

export function upcastAll(raws: readonly unknown[]): CurrentGoalEvent[] {
  return raws.map((r) => upcast(r));
}
