```typescript
export type MatchEvent =
  | { type: "MatchFullTime"; home: string; away: string; homeGoals: number; awayGoals: number };

export interface StandingsRow {
  club: string;
  played: number;
  points: number;
}

export type StandingsView = Record<string, StandingsRow>;

export const emptyStandings: StandingsView = {};

export function project(view: StandingsView, e: MatchEvent): StandingsView {
  const h = view[e.home] ?? { club: e.home, played: 0, points: 0 };
  const a = view[e.away] ?? { club: e.away, played: 0, points: 0 };
  const hw = e.homeGoals > e.awayGoals, draw = e.homeGoals === e.awayGoals;
  return {
    ...view,
    [e.home]: { ...h, played: h.played + 1, points: h.points + (hw ? 3 : draw ? 1 : 0) },
    [e.away]: { ...a, played: a.played + 1, points: a.points + (!hw && !draw ? 3 : draw ? 1 : 0) },
  };
}

export interface EventBatch<E> {
  events: ReadonlyArray<{ position: bigint; event: E }>;
  nextFrom: bigint | null;
}

export interface EventStoreReader<E> {
  readBatch(from: bigint, batchSize: number): Promise<EventBatch<E>>;
}

export interface ReadStore {
  persist(view: StandingsView, cursor: bigint): Promise<void>;
}

export interface RebuildOptions {
  from: bigint;
  batchSize: number;
  store: EventStoreReader<MatchEvent>;
  persist: ReadStore;
  initial?: StandingsView;
  onProgress?: (cursor: bigint) => void;
}

export async function rebuild(options: RebuildOptions): Promise<void> {
  let view: StandingsView = options.initial ?? emptyStandings;
  let cursor: bigint | null = options.from;
  async function main() {
    while (cursor !== null) {
      const batch = await options.store.readBatch(cursor, options.batchSize);
      for (const { event } of batch.events) view = project(view, event);
      const last = batch.events[batch.events.length - 1];
      if (last) {
        await options.persist.persist(view, last.position);
        options.onProgress?.(last.position);
      }
      cursor = batch.nextFrom;
    }
  }
  await main();
}
```

