export type GoalEvent =
  | { type: "GoalScored"; matchId: string; scorer: string; minute: number }
  | { type: "GoalDisallowed"; matchId: string; scorer: string };

export interface PlayerStats {
  player: string;
  goals: number;
  disallowed: number;
}

export type GoalStatsView = Record<string, PlayerStats>;

export function project(view: GoalStatsView, e: GoalEvent): GoalStatsView {
  switch (e.type) {
    case "GoalScored": {
      const prev = view[e.scorer] ?? { player: e.scorer, goals: 0, disallowed: 0 };
      return { ...view, [e.scorer]: { ...prev, goals: prev.goals + 1 } };
    }
    case "GoalDisallowed": {
      const prev = view[e.scorer] ?? { player: e.scorer, goals: 0, disallowed: 0 };
      return { ...view, [e.scorer]: { ...prev, disallowed: prev.disallowed + 1 } };
    }
    default: { const _n: never = e; return view; }
  }
}

export interface EventBatch<E> {
  events: ReadonlyArray<{ position: bigint; event: E }>;
  nextFrom: bigint | null;
}

export interface EventStoreReader<E> {
  readBatch(from: bigint, size: number): Promise<EventBatch<E>>;
}

export interface ReadStore {
  persist(view: GoalStatsView, cursor: bigint): Promise<void>;
}

export async function rebuildGoalStats(
  from: bigint,
  batchSize: number,
  reader: EventStoreReader<GoalEvent>,
  store: ReadStore,
): Promise<void> {
  let view: GoalStatsView = {};
  let cursor: bigint | null = from;
  async function main() {
    while (cursor !== null) {
      const batch = await reader.readBatch(cursor, batchSize);
      for (const { event } of batch.events) view = project(view, event);
      const last = batch.events[batch.events.length - 1];
      if (last) await store.persist(view, last.position);
      cursor = batch.nextFrom;
    }
  }
  await main();
}
