export type SanctionEvent =
  | { type: "SanctionIssued"; playerId: string; matchId: string }
  | { type: "SanctionServed"; playerId: string }
  | { type: "MatchFullTime"; matchId: string };

export type SuspensionCommand =
  | { type: "SuspendPlayer"; playerId: string; reason: string };

export interface SagaState {
  tally: Record<string, number>;
}

export const initialSaga: SagaState = { tally: {} };

export function react(state: SagaState, event: SanctionEvent): { next: SagaState; command: SuspensionCommand | null } {
  switch (event.type) {
    case "SanctionIssued": {
      const count = (state.tally[event.playerId] ?? 0) + 1;
      const next: SagaState = { tally: { ...state.tally, [event.playerId]: count } };
      if (count >= 3) {
        return {
          next: { tally: { ...next.tally, [event.playerId]: 0 } },
          command: { type: "SuspendPlayer", playerId: event.playerId, reason: "Accumulated sanctions" },
        };
      }
      return { next, command: null };
    }
    case "SanctionServed":
      return { next: state, command: null };
    case "MatchFullTime":
      return { next: state, command: null };
    default: {
      const _never: never = event;
      return { next: state, command: null };
    }
  }
}

export function runSaga(events: readonly SanctionEvent[]): SuspensionCommand[] {
  let state = initialSaga;
  const out: SuspensionCommand[] = [];
  for (const e of events) {
    const { next, command } = react(state, e);
    state = next;
    if (command) out.push(command);
  }
  return out;
}
```

A process manager is a pure `react` function: it ignores events it does not care about (returning `null`) and emits the next command for the ones it does. State, if any, lives in its own subscription stream — the same way any other aggregate does.

