export type GoalDomainEvent =
  | { type: "GoalRecorded"; matchId: string; scorerId: string; minute: number }
  | { type: "GoalDisallowed"; matchId: string; scorerId: string; reason: string }
  | { type: "GoalReviewed"; matchId: string; reviewerId: string };

export type IntegrationEvent =
  | { schema: "goal.scored.v1"; payload: { matchId: string; scorerId: string; minute: number } }
  | { schema: "goal.disallowed.v1"; payload: { matchId: string; scorerId: string; reason: string } };

export function translate(event: GoalDomainEvent): IntegrationEvent | null {
  switch (event.type) {
    case "GoalRecorded":
      return {
        schema: "goal.scored.v1",
        payload: { matchId: event.matchId, scorerId: event.scorerId, minute: event.minute },
      };
    case "GoalDisallowed":
      return {
        schema: "goal.disallowed.v1",
        payload: { matchId: event.matchId, scorerId: event.scorerId, reason: event.reason },
      };
    case "GoalReviewed":
      // internal VAR activity doesn't leave the bounded context
      return null;
    default: {
      const _never: never = event;
      return null;
    }
  }
}

export function translateAll(events: readonly GoalDomainEvent[]): IntegrationEvent[] {
  return events.flatMap((e) => {
    const i = translate(e);
    return i === null ? [] : [i];
  });
}
