```typescript
export type MatchDomainEvent =
  | { type: "MatchFullTime"; id: string; homeGoals: number; awayGoals: number };

export interface OutboxRow {
  id: string;
  schema: string;
  payload: string;
  publishedAt: string | null;
}

export interface TransactionalDb {
  insertOutbox(rows: readonly OutboxRow[]): Promise<void>;
  appendToStream(stream: string, events: readonly MatchDomainEvent[], opts: { expectedRevision: bigint | "no_stream" }): Promise<void>;
}

export interface UnitOfWork {
  run<T>(body: (db: TransactionalDb) => Promise<T>): Promise<T>;
}

export function translate(e: MatchDomainEvent): OutboxRow {
  return {
    id: `${e.type}:${e.id}`,
    schema: "match.fulltime.v1",
    payload: JSON.stringify({ id: e.id, homeGoals: e.homeGoals, awayGoals: e.awayGoals }),
    publishedAt: null,
  };
}

// A separate publisher worker polls the outbox, sends each row to the broker,
// and then marks it published. That worker lives outside this file.
export async function appendWithOutbox(
  uow: UnitOfWork,
  stream: string,
  events: readonly MatchDomainEvent[],
  expected: bigint | "no_stream",
): Promise<void> {
  const rows = events.map(translate);
  await uow.run(async (db) => {
    await db.appendToStream(stream, events, { expectedRevision: expected });
    await db.insertOutbox(rows);
  });
}
