```typescript
import { Effect } from "effect";

export type GoalEvent = { type: "GoalRecorded"; scorerId: string; matchId: string; minute: number };

export type ExpectedRevision = bigint | "no_stream";

export interface EventStore {
  appendToStream(stream: string, events: readonly GoalEvent[], opts: { expectedRevision: ExpectedRevision }): Promise<{ nextRevision: bigint }>;
}

export class GoalAppendError extends Error {
  constructor(public readonly stream: string) {
    super(`GOAL_APPEND_FAILED:${stream}`);
    this.name = "GoalAppendError";
  }
}

export function appendGoal(store: EventStore, stream: string, event: GoalEvent, expected: ExpectedRevision) {
  return Effect.gen(function* () {
    const result = yield* Effect.tryPromise({
      try: () => store.appendToStream(stream, [event], { expectedRevision: expected }),
      catch: () => new GoalAppendError(stream),
    });
    return result.nextRevision;
  });
}
